import React from 'react';
import '../App.css';

class setTimer extends React.Component {
  render() {
    const {minuteInput, secondInput} = this.props;
    return(
      <div className="timer">
        <p>Quanto tempo de pausa?</p>
        <input type="number" min="0" max="59" placeholder="mm" ref={(input) => minuteInput = input}></input>&nbsp;:&nbsp;
        <input type="number" min="0" max="59" placeholder="ss" ref={(input) => secondInput = input}></input>
      </div>
    )
  }
}

export default setTimer
